package ir.tahamohamadi.blog.tag; import org.springframework.data.jpa.repository.*; import org.springframework.data.repository.query.Param; import java.util.*; public interface BlogPostTagRepository extends JpaRepository<BlogPostTag,BlogPostTagId>{ @Query("select value from BlogPostTag value join fetch value.tag where value.id.blogPostId=:postId order by value.tag.tagKey asc") List<BlogPostTag> findByPostIdWithTagOrderByTagKey(@Param("postId") UUID postId); void deleteByIdBlogPostId(UUID blogPostId); }
